package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.VariableDeclarator;
import com.github.javaparser.ast.type.ClassOrInterfaceType;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;

import java.io.File;
import java.nio.file.Files;
import java.nio.file.Paths;

public class Main {
    public static void main(String[] args) throws Exception {
        if (args.length < 1) {
            System.err.println("Usage: java Main <path-to-java-file>");
            System.exit(1);
        }

        String filePath = args[0];
        File file = new File(filePath);

        if (!file.exists()) {
            System.err.println("File not found: " + filePath);
            System.exit(1);
        }

        CompilationUnit cu = StaticJavaParser.parse(file);

        // Fix: Change SortedMap<MOScope, ManagedObject> to SortedMap<MOScope, ManagedObject<?>>
        cu.accept(new ManagedObjectFixVisitor(), null);

        Files.write(Paths.get(filePath), cu.toString().getBytes());
        System.out.println("Transformation applied successfully to: " + filePath);
    }

    static class ManagedObjectFixVisitor extends VoidVisitorAdapter<Void> {
        @Override
        public void visit(VariableDeclarator n, Void arg) {
            super.visit(n, arg);

            // Check if this variable has a type that is SortedMap with ManagedObject as value type
            if (n.getType().isArrayType()) {
                return;
            }

            ClassOrInterfaceType type = n.getType().asClassOrInterfaceType();

            // Check if this is a SortedMap type
            if (type.getNameAsString().equals("SortedMap") && type.getTypeArguments().isPresent()) {
                var typeArgs = type.getTypeArguments().get();
                if (typeArgs.size() == 2) {
                    var valueType = typeArgs.get(1);
                    // Check if value type is ManagedObject without wildcard
                    if (valueType instanceof ClassOrInterfaceType) {
                        ClassOrInterfaceType valueClassType = (ClassOrInterfaceType) valueType;
                        if (valueClassType.getNameAsString().equals("ManagedObject") && 
                            !valueClassType.getTypeArguments().isPresent()) {
                            // Add wildcard type argument: ManagedObject<?>
                            ClassOrInterfaceType wildcardType = new ClassOrInterfaceType();
                            wildcardType.setName("ManagedObject");
                            var wildcardArgs = new java.util.ArrayList<com.github.javaparser.ast.type.Type<?>>();
                            wildcardArgs.add(new com.github.javaparser.ast.type.WildcardType());
                            wildcardType.setTypeArguments(wildcardArgs);
                            typeArgs.set(1, wildcardType);
                        }
                    }
                }
            }
        }
    }
}

